import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const statusColor = { pending: '#f39c12', approved: '#27ae60', rejected: '#e74c3c', expired: '#95a5a6' };

const s = {
  page: { padding: 32, maxWidth: 960, margin: '0 auto' },
  greeting: { fontSize: 26, fontWeight: 700, color: '#1a3a5c', marginBottom: 4 },
  sub: { color: '#888', marginBottom: 28 },
  grid3: { display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 16, marginBottom: 28 },
  statCard: { background: '#fff', borderRadius: 14, padding: '20px 16px', boxShadow: '0 2px 12px rgba(0,0,0,0.07)', textAlign: 'center' },
  statNum: { fontSize: 32, fontWeight: 800, marginBottom: 4 },
  statLabel: { fontSize: 12, color: '#888', fontWeight: 600, textTransform: 'uppercase', letterSpacing: 0.5 },
  card: { background: '#fff', borderRadius: 14, padding: '24px', boxShadow: '0 2px 12px rgba(0,0,0,0.07)', marginBottom: 24 },
  sectionTitle: { fontSize: 17, fontWeight: 700, color: '#1a3a5c', marginBottom: 16, display: 'flex', alignItems: 'center', gap: 8 },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { background: '#1a3a5c', color: '#fff', padding: '11px 14px', textAlign: 'left', fontSize: 13 },
  td: { padding: '11px 14px', borderBottom: '1px solid #f0f0f0', fontSize: 13 },
  badge: { padding: '3px 12px', borderRadius: 20, fontSize: 12, fontWeight: 700 },
  btn: { padding: '10px 22px', borderRadius: 9, fontWeight: 700, fontSize: 14, cursor: 'pointer', border: 'none', textDecoration: 'none', display: 'inline-block' },
  renewBtn: { padding: '6px 16px', background: '#2980b9', color: '#fff', border: 'none', borderRadius: 7, cursor: 'pointer', fontSize: 13, fontWeight: 600 },
  payBtn: { padding: '6px 16px', background: '#27ae60', color: '#fff', border: 'none', borderRadius: 7, cursor: 'pointer', fontSize: 13, fontWeight: 600 },
};

// Timeline steps for application journey
const APPLICATION_STEPS = [
  { key: 'applied', label: 'Applied', icon: '📝', desc: 'Application submitted' },
  { key: 'docs_verified', label: 'Docs Verified', icon: '🤖', desc: 'AI verified documents' },
  { key: 'payment', label: 'Payment', icon: '💳', desc: 'Fee payment pending' },
  { key: 'admin_review', label: 'Admin Review', icon: '🛡️', desc: 'Under admin review' },
  { key: 'approved', label: 'Approved', icon: '✅', desc: 'Pass issued' },
];

function getStepIndex(status) {
  if (status === 'approved') return 4;
  if (status === 'rejected') return 3;
  if (status === 'pending') return 2; // payment done, awaiting admin
  return 1;
}

function PassTimeline({ pass }) {
  const currentStep = getStepIndex(pass.status);
  return (
    <div style={{ padding: '16px 0 8px' }}>
      <div style={{ display: 'flex', alignItems: 'flex-start', gap: 0 }}>
        {APPLICATION_STEPS.map((step, i) => {
          const done = i < currentStep;
          const active = i === currentStep;
          const failed = pass.status === 'rejected' && i === currentStep;
          return (
            <div key={step.key} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', position: 'relative' }}>
              {/* Connector line */}
              {i > 0 && (
                <div style={{
                  position: 'absolute', top: 18, right: '50%', width: '100%', height: 3,
                  background: done ? '#27ae60' : '#e0e0e0', zIndex: 0
                }} />
              )}
              {/* Circle */}
              <div style={{
                width: 36, height: 36, borderRadius: '50%', zIndex: 1,
                background: failed ? '#e74c3c' : done ? '#27ae60' : active ? '#2980b9' : '#e0e0e0',
                color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 16, fontWeight: 700, border: active ? '3px solid #1a5276' : '3px solid transparent',
                boxShadow: active ? '0 0 0 3px #d6eaf8' : 'none'
              }}>
                {failed ? '✗' : done ? '✓' : step.icon}
              </div>
              <div style={{ fontSize: 11, fontWeight: 700, color: done ? '#27ae60' : active ? '#2980b9' : '#aaa', marginTop: 6, textAlign: 'center' }}>{step.label}</div>
              <div style={{ fontSize: 10, color: '#bbb', textAlign: 'center', maxWidth: 70 }}>{step.desc}</div>
            </div>
          );
        })}
      </div>

      {/* Payment CTA */}
      {pass.status === 'pending' && (
        <PaymentSection pass={pass} />
      )}
    </div>
  );
}

function PaymentSection({ pass }) {
  const [paying, setPaying] = useState(false);
  const [paid, setPaid] = useState(false);

  const feeMap = { monthly: 300, quarterly: 800, yearly: 2800 };
  const fee = feeMap[pass.passType] || 300;

  const handlePayment = () => {
    setPaying(true);
    // Simulated payment gateway flow
    setTimeout(() => {
      setPaying(false);
      setPaid(true);
    }, 2500);
  };

  if (paid) return (
    <div style={{ background: '#eafaf1', border: '1.5px solid #27ae60', borderRadius: 10, padding: 14, marginTop: 16, textAlign: 'center' }}>
      <div style={{ fontSize: 15, fontWeight: 700, color: '#27ae60' }}>✅ Payment of ₹{fee} Successful!</div>
      <div style={{ fontSize: 12, color: '#888', marginTop: 4 }}>Transaction ID: TXN{Date.now()} · Your pass is now under admin review.</div>
    </div>
  );

  return (
    <div style={{ background: '#fff8e1', border: '1.5px solid #f39c12', borderRadius: 10, padding: 16, marginTop: 16 }}>
      <div style={{ fontWeight: 700, color: '#856404', fontSize: 14, marginBottom: 8 }}>💳 Payment Required</div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 10 }}>
        <div>
          <div style={{ fontSize: 13, color: '#555' }}>Route: <strong>{pass.from} → {pass.to}</strong></div>
          <div style={{ fontSize: 13, color: '#555' }}>Pass Type: <strong>{pass.passType}</strong> · Fee: <strong style={{ color: '#27ae60', fontSize: 16 }}>₹{fee}</strong></div>
        </div>
        <button style={s.payBtn} onClick={handlePayment} disabled={paying}>
          {paying ? '⏳ Processing...' : `💳 Pay ₹${fee} Now`}
        </button>
      </div>
      {paying && (
        <div style={{ marginTop: 10, fontSize: 12, color: '#888' }}>
          🔒 Connecting to payment gateway... please wait
        </div>
      )}
    </div>
  );
}

function RenewalSection({ passes, onRenew }) {
  const renewalCandidates = passes.filter(p =>
    p.status === 'approved' || p.status === 'expired'
  );

  if (renewalCandidates.length === 0) return null;

  return (
    <div style={s.card}>
      <div style={s.sectionTitle}>🔄 Renewal Section</div>
      {renewalCandidates.map(p => {
        const expiring = p.validTo && new Date(p.validTo) - new Date() < 7 * 24 * 60 * 60 * 1000;
        const expired = p.status === 'expired';
        return (
          <div key={p._id} style={{
            display: 'flex', justifyContent: 'space-between', alignItems: 'center',
            padding: '14px 16px', borderRadius: 10, marginBottom: 10,
            background: expired ? '#fdecea' : expiring ? '#fff8e1' : '#f0f9ff',
            border: `1.5px solid ${expired ? '#e74c3c' : expiring ? '#f39c12' : '#2980b9'}`
          }}>
            <div>
              <div style={{ fontWeight: 700, fontSize: 14, color: '#1a3a5c' }}>{p.from} → {p.to}</div>
              <div style={{ fontSize: 12, color: '#666', marginTop: 3 }}>
                Pass #{p.passNumber} · {p.passType}
                {p.validTo && <span> · Expires: <strong>{new Date(p.validTo).toLocaleDateString()}</strong></span>}
              </div>
              {expired && <div style={{ fontSize: 12, color: '#e74c3c', marginTop: 3, fontWeight: 600 }}>⚠️ This pass has expired</div>}
              {expiring && !expired && <div style={{ fontSize: 12, color: '#f39c12', marginTop: 3, fontWeight: 600 }}>⏰ Expiring soon! Renew now</div>}
            </div>
            <button style={s.renewBtn} onClick={() => onRenew(p._id)}>🔄 Renew</button>
          </div>
        );
      })}
    </div>
  );
}

export default function StudentDashboard() {
  const { user } = useAuth();
  const [passes, setPasses] = useState([]);
  const [selectedPass, setSelectedPass] = useState(null);
  const navigate = useNavigate();

  const load = () => {
    axios.get('/api/pass/my').then(r => {
      setPasses(r.data);
      if (r.data.length > 0) setSelectedPass(r.data[0]);
    }).catch(() => {});
  };

  useEffect(() => { load(); }, []);

  const renew = async (id) => {
    await axios.post(`/api/pass/renew/${id}`, { passType: 'monthly' });
    load();
  };

  const activePass = passes.find(p => p.status === 'approved');
  const pendingPass = passes.find(p => p.status === 'pending');
  const approved = passes.filter(p => p.status === 'approved').length;
  const pending = passes.filter(p => p.status === 'pending').length;
  const expired = passes.filter(p => p.status === 'expired').length;

  return (
    <div style={s.page}>
      {/* Header */}
      <div style={{ marginBottom: 24 }}>
        <div style={s.greeting}>Welcome, {user?.name} 👋</div>
        <div style={s.sub}>USN: {user?.usn} · NIE Mysuru · {new Date().toLocaleDateString('en-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</div>
      </div>

      {/* Stats */}
      <div style={s.grid3}>
        <div style={s.statCard}><div style={{ ...s.statNum, color: '#2980b9' }}>{passes.length}</div><div style={s.statLabel}>Total</div></div>
        <div style={s.statCard}><div style={{ ...s.statNum, color: '#27ae60' }}>{approved}</div><div style={s.statLabel}>Approved</div></div>
        <div style={s.statCard}><div style={{ ...s.statNum, color: '#f39c12' }}>{pending}</div><div style={s.statLabel}>Pending</div></div>
        <div style={s.statCard}><div style={{ ...s.statNum, color: '#95a5a6' }}>{expired}</div><div style={s.statLabel}>Expired</div></div>
      </div>

      {/* Active Pass Banner */}
      {activePass && (
        <div style={{ background: 'linear-gradient(135deg, #1a3a5c, #2980b9)', borderRadius: 14, padding: '22px 26px', marginBottom: 24, color: '#fff' }}>
          <div style={{ fontSize: 12, opacity: 0.8, marginBottom: 4, textTransform: 'uppercase', letterSpacing: 1 }}>🟢 Active Bus Pass</div>
          <div style={{ fontSize: 22, fontWeight: 800, marginBottom: 6 }}>{activePass.from} → {activePass.to}</div>
          <div style={{ display: 'flex', gap: 24, flexWrap: 'wrap', fontSize: 13, opacity: 0.9 }}>
            <span>Pass #: <strong>{activePass.passNumber}</strong></span>
            <span>Type: <strong>{activePass.passType}</strong></span>
            <span>Valid till: <strong>{new Date(activePass.validTo).toLocaleDateString()}</strong></span>
          </div>
        </div>
      )}

      {/* Quick Actions */}
      <div style={{ display: 'flex', gap: 12, marginBottom: 24, flexWrap: 'wrap' }}>
        <Link to="/apply" style={{ ...s.btn, background: '#1a3a5c', color: '#fff' }}>+ Apply for Pass</Link>
        <Link to="/my-passes" style={{ ...s.btn, background: '#fff', color: '#1a3a5c', border: '2px solid #1a3a5c' }}>📋 All Passes</Link>
        {activePass && <button style={{ ...s.btn, background: '#fff', color: '#27ae60', border: '2px solid #27ae60' }} onClick={() => renew(activePass._id)}>🔄 Renew Pass</button>}
      </div>

      {/* Renewal Section */}
      <RenewalSection passes={passes} onRenew={renew} />

      {/* Application Journey Tracker */}
      {passes.length > 0 && (
        <div style={s.card}>
          <div style={s.sectionTitle}>🗺️ Application Journey Tracker</div>

          {/* Pass selector if multiple */}
          {passes.length > 1 && (
            <div style={{ marginBottom: 16 }}>
              <select style={{ padding: '8px 12px', borderRadius: 8, border: '1.5px solid #ddd', fontSize: 13, background: '#fff' }}
                onChange={e => setSelectedPass(passes.find(p => p._id === e.target.value))}
                value={selectedPass?._id || ''}>
                {passes.map(p => (
                  <option key={p._id} value={p._id}>{p.from} → {p.to} · {p.status} · {new Date(p.appliedAt).toLocaleDateString()}</option>
                ))}
              </select>
            </div>
          )}

          {selectedPass && <PassTimeline pass={selectedPass} />}
        </div>
      )}

      {/* Pending Payment Alert */}
      {pendingPass && (
        <div style={{ background: '#fff3cd', border: '1.5px solid #ffc107', borderRadius: 12, padding: '14px 18px', marginBottom: 24 }}>
          <div style={{ fontWeight: 700, color: '#856404', marginBottom: 4 }}>⚠️ Action Required — Payment Pending</div>
          <div style={{ fontSize: 13, color: '#664d03' }}>Your application for <strong>{pendingPass.from} → {pendingPass.to}</strong> is awaiting payment. Complete payment to proceed to admin review.</div>
        </div>
      )}

      {/* Recent Applications Table */}
      <div style={s.card}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
          <div style={s.sectionTitle}>📋 Recent Applications</div>
          <Link to="/my-passes" style={{ fontSize: 13, color: '#2980b9', fontWeight: 600, textDecoration: 'none' }}>View All →</Link>
        </div>
        <table style={s.table}>
          <thead>
            <tr>
              <th style={s.th}>Pass No</th>
              <th style={s.th}>Route</th>
              <th style={s.th}>Type</th>
              <th style={s.th}>Applied</th>
              <th style={s.th}>Valid Till</th>
              <th style={s.th}>Status</th>
            </tr>
          </thead>
          <tbody>
            {passes.slice(0, 5).map(p => (
              <tr key={p._id}>
                <td style={s.td}>{p.passNumber || '—'}</td>
                <td style={s.td}><strong>{p.from}</strong> → {p.to}</td>
                <td style={s.td}>{p.passType}</td>
                <td style={s.td}>{new Date(p.appliedAt).toLocaleDateString()}</td>
                <td style={s.td}>{p.validTo ? new Date(p.validTo).toLocaleDateString() : '—'}</td>
                <td style={s.td}>
                  <span style={{ ...s.badge, background: statusColor[p.status] + '22', color: statusColor[p.status] }}>
                    {p.status.toUpperCase()}
                  </span>
                </td>
              </tr>
            ))}
            {passes.length === 0 && (
              <tr><td colSpan={6} style={{ ...s.td, textAlign: 'center', color: '#aaa', padding: 30 }}>
                No applications yet. <Link to="/apply" style={{ color: '#2980b9' }}>Apply now →</Link>
              </td></tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Bus Info Card */}
      <div style={{ ...s.card, background: 'linear-gradient(135deg, #f8fbff, #e8f4fd)' }}>
        <div style={s.sectionTitle}>🚌 Bus Pass Information</div>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16 }}>
          {[
            { icon: '📅', title: 'Monthly Pass', price: '₹300', desc: 'Valid for 1 month' },
            { icon: '📆', title: 'Quarterly Pass', price: '₹800', desc: 'Valid for 3 months' },
            { icon: '🗓️', title: 'Yearly Pass', price: '₹2800', desc: 'Valid for 12 months' },
          ].map(item => (
            <div key={item.title} style={{ background: '#fff', borderRadius: 10, padding: '16px', textAlign: 'center', boxShadow: '0 1px 6px rgba(0,0,0,0.06)' }}>
              <div style={{ fontSize: 28 }}>{item.icon}</div>
              <div style={{ fontWeight: 700, fontSize: 14, color: '#1a3a5c', marginTop: 6 }}>{item.title}</div>
              <div style={{ fontSize: 22, fontWeight: 800, color: '#27ae60', margin: '4px 0' }}>{item.price}</div>
              <div style={{ fontSize: 12, color: '#888' }}>{item.desc}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
